mapper.select:
select article.*, category.name as categoryName
from blog.article left outer join blog.category on article.category_id = category.id

    and status = #{article.status}
    and title like concat('%', #{article.title}, '%')
    and category_id = #{article.categoryId}
    and user_id = #{article.userId}
    and article.create_time = #{article.createTime}
